// AQUI VOCÊ COLOCA SUA VARIÁVEL DO NÚMERO ↓
let numeroWhatsApp = $input.first().json.body.data.key.remoteJid;  // ← SUA VARIÁVEL AQUI
// ────────────────────────────────────────────────────────────────────

// Remove @s.whatsapp.net, o sinal de + e corrige o formato do celular brasileiro
let numero = numeroWhatsApp.replace('@s.whatsapp.net', '').replace('+', '');

// Se tem 12 dígitos (55 + área + 8 dígitos), adiciona o 9
if (numero.length === 12 && numero.startsWith('55')) {
    let area = numero.substring(2, 4);
    let telefone = numero.substring(4);

    // Adiciona o 9 para celular
    numero = '55' + area + '9' + telefone;
}

// Retorna como array de objetos (formato esperado pela plataforma)
return [{
    telefone: numero
}];

